/// Dispatches one IRP through the unified async-capable receive boundary.
fn dispatch(device: PDEVICE_OBJECT, irp: PIRP, major: DispatchMajor) -> NTSTATUS {
    let received = match ReceivedIrp::decode(device, irp) {
        Ok(received) => received,
        Err(error) => return ReceivedIrp::complete_decode_error(irp, error),
    };

    match dispatch_policy(major) {
        DispatchPolicy::Immediate => {
            let target = received.target();
            received.complete_result(execute_immediate(major, target))
        }
        DispatchPolicy::Queued => DeviceIrpQueue::receive_async(received),
    }
}

/// Queue policy for a received major function.
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum DispatchPolicy {
    /// Complete during the dispatch callback.
    Immediate,
    /// Mark pending and execute from the device queue worker.
    Queued,
}

/// Returns the queue policy for a major function.
const fn dispatch_policy(major: DispatchMajor) -> DispatchPolicy {
    match major {
        DispatchMajor::Close
        | DispatchMajor::Cleanup
        | DispatchMajor::DeviceControl
        | DispatchMajor::LockControl
        | DispatchMajor::Shutdown => DispatchPolicy::Immediate,
        DispatchMajor::Create
        | DispatchMajor::Read
        | DispatchMajor::Write
        | DispatchMajor::QueryInformation
        | DispatchMajor::SetInformation
        | DispatchMajor::QueryVolumeInformation
        | DispatchMajor::SetVolumeInformation
        | DispatchMajor::DirectoryControl
        | DispatchMajor::FileSystemControl
        | DispatchMajor::FlushBuffers
        | DispatchMajor::QueryEa
        | DispatchMajor::SetEa
        | DispatchMajor::QuerySecurity
        | DispatchMajor::SetSecurity => DispatchPolicy::Queued,
    }
}

/// Executes a queued IRP after a worker removes it from the device queue.
/// # Errors
///
/// Returns an error when the queued IRP stack cannot be decoded or the selected request handler
/// rejects the request.
#[cfg_attr(
    test,
    expect(
        dead_code,
        reason = "kernel work-item worker is compiled out in unit tests"
    )
)]
pub(crate) fn execute_queued(target: DispatchTarget) -> DriverResult<IrpCompletion> {
    execute_major(target.current_stack()?.major()?, target)
}

/// Executes an immediate IRP during the dispatch callback.
/// # Errors
///
/// Returns an error when an immediate request cannot be decoded or is not valid for immediate
/// execution.
fn execute_immediate(major: DispatchMajor, target: DispatchTarget) -> DriverResult<IrpCompletion> {
    match major {
        DispatchMajor::Cleanup => cleanup_immediate(target),
        DispatchMajor::Close
        | DispatchMajor::DeviceControl
        | DispatchMajor::LockControl
        | DispatchMajor::Shutdown => execute_major(major, target),
        DispatchMajor::Create
        | DispatchMajor::Read
        | DispatchMajor::Write
        | DispatchMajor::QueryInformation
        | DispatchMajor::SetInformation
        | DispatchMajor::QueryVolumeInformation
        | DispatchMajor::SetVolumeInformation
        | DispatchMajor::DirectoryControl
        | DispatchMajor::FileSystemControl
        | DispatchMajor::FlushBuffers
        | DispatchMajor::QueryEa
        | DispatchMajor::SetEa
        | DispatchMajor::QuerySecurity
        | DispatchMajor::SetSecurity => Err(DriverError::InvalidDeviceRequest),
    }
}

/// Cancels queued IRPs for the same file object, then runs normal cleanup.
/// # Errors
///
/// Returns an error when cleanup stack decoding, queue lookup, or file cleanup handling fails.
fn cleanup_immediate(target: DispatchTarget) -> DriverResult<IrpCompletion> {
    let file_object = target.current_stack()?.file_object()?;
    let queue = DeviceIrpQueue::from_device(target.device())?;
    DeviceIrpQueue::cancel_file_object(queue, file_object);
    crate::request::file_info::cleanup(target)
}

/// Executes the request implementation for a typed major function.
/// # Errors
///
/// Returns an error when the selected request implementation rejects the decoded IRP.
fn execute_major(major: DispatchMajor, target: DispatchTarget) -> DriverResult<IrpCompletion> {
    match major {
        DispatchMajor::Create => crate::request::create::execute(target),
        DispatchMajor::Close => crate::request::file_info::close(target),
        DispatchMajor::Cleanup => crate::request::file_info::cleanup(target),
        DispatchMajor::Read => crate::request::file_info::read(target),
        DispatchMajor::Write => crate::request::file_info::write(target),
        DispatchMajor::QueryInformation => crate::request::file_info::query(target),
        DispatchMajor::SetInformation => crate::request::file_info::set(target),
        DispatchMajor::QueryVolumeInformation => crate::request::volume_info::query(target),
        DispatchMajor::SetVolumeInformation => crate::request::volume_info::set(target),
        DispatchMajor::DirectoryControl => crate::request::file_info::directory_control(target),
        DispatchMajor::FileSystemControl => crate::request::file_system_control::execute(target),
        DispatchMajor::DeviceControl => crate::request::file_system_control::device_control(target),
        DispatchMajor::FlushBuffers => crate::request::file_info::flush(target),
        DispatchMajor::QueryEa => crate::request::ea::query(target),
        DispatchMajor::SetEa => crate::request::ea::set(target),
        DispatchMajor::LockControl => crate::request::file_info::lock_control(target),
        DispatchMajor::Shutdown => Ok(IrpCompletion::EMPTY),
        DispatchMajor::QuerySecurity => crate::request::security::query(target),
        DispatchMajor::SetSecurity => crate::request::security::set(target),
    }
}
